INSERT INTO content (page, section, title, content, image_path) VALUES ('about', 'main', 'Lycee S t Alexandre Sauli De Muhura Peres Barnabites', 'Lycee S t Alexandre Sauli De Muhura Peres Barnabites Home About Academic Staff Events Announcements Departments Fashion Design (FAD) Accounting ICT Software Development (SOD) Computer Systems & Architecture (CSA) Networking & Internet Technology (NIT) Contact Login Login About Our School Lycee Saint Alexandre Sauli De Muhura is committed to nurturing bright minds and talented individuals. With modern facilities, qualified teachers, and strong moral formation, we prepare students for a future of excellence, leadership, and service. Who We Are Lycee Saint Alexandre Sauli de Muhura is a Catholic secondary school located in the Eastern Province of Rwanda, founded under the spiritual guidance of the Barnabite Fathers . We provide a balanced education integrating academic excellence, Christian morals, discipline, and practical skills. Our learning environment encourages students to grow intellectually, spiritually, creatively, and socially, forming responsible citizens equipped for today’s world. Students 0 Teachers / Trainers 0 Our Mission To provide quality education rooted in Christian values, empowering students to become disciplined, skilled, and responsible leaders. Our Vision To be a leading educational institution nurturing integrity, innovation, academic excellence, and service to God and society. Core Values Respect & Discipline Integrity Excellence Faith & Service Teamwork Academic Programs Offered SOD Software Development NIT Networking & Internet Technology CSA Computer Systems & Architecture FAD Fashion & Design ACC Accounting & Business Management Who Was Saint Alexandre Sauli? Saint Alexandre Sauli (1534–1592) was a Barnabite priest, bishop, and scholar, known as the "Apostle of Corsica" . He dedicated his life to education, peacebuilding, and spiritual guidance. Sauli studied in Milan and became a prominent figure in church reform. He was appointed Bishop of Aleria, Corsica, where he worked tirelessly to educate clergy and laity alike. His writings emphasized moral integrity, leadership, and devotion to God. Sauli''s humility and dedication to youth education inspired the identity and mission of our school. Today, Lycee Saint Alexandre Sauli de Muhura embodies his vision by integrating faith, discipline, and knowledge, preparing students for a life of service, responsibility, and excellence. Read More About Sauli The Barnabite Fathers The Barnabites (Clerics Regular of St. Paul) were founded in 1530 by St. Anthony Maria Zaccaria. Their mission includes youth education, pastoral care, moral guidance, and community service. Lycee Saint Alexandre Sauli de Muhura is proudly guided by Barnabite principles of faith, charity, humility, and intellectual formation. Why Choose Our School? Qualified Teachers Strong Moral Foundation Modern Learning Facilities Practical & Technical Skills Developers IRASUBIZA Jean Cadeau IHIRWE Aimee Saina HABAKUBAHO Brainy Justin TUMURAMYWE Placide Email: lycemuhur@gmail.com School Location Rwanda, Eastern Province Gatsibo District Muhura Sector, Taba Cell Kanyinya Village Follow Us © 2025 LYCEE SAINT ALEXANDRE SAULI DE MUHURA — All Rights Reserved', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('academic', 'main', 'Lycee S t Alexandre Sauli De Muhura Peres Barnabites', 'Lycee S t Alexandre Sauli De Muhura Peres Barnabites Home About Academic Staff Events Announcements Departments Fashion Design (FAD) Accounting ICT Software Development (SOD) Computer Systems & Architecture (CSA) Networking & Internet Technology (NIT) Contact Login Login School''s Academic Programs Through a combination of theory, practice, and real-world applications, our academic programs empower students to become confident, skilled, and adaptable professionals ready to make an impact in their chosen fields. Fashion Design Students learn creative design, pattern making, and garment construction. Emphasis on discipline, craftsmanship, teamwork, and ethical practices inspired by Catholic values. ICT Includes Software Development, Computer System & Architecture, and Networking. Focus on critical thinking, problem-solving, and modern technology skills, combined with discipline and integrity. Accounting Students learn bookkeeping, financial management, and business ethics. Discipline, organization, and accuracy are emphasized, aligned with our Barnabite guidance. NESA Chronograms Click below to view the official NESA academic schedules directly on this page. Term 1 Chronogram "> Term 1 View the detailed schedule for Term 1. Term 2 Chronogram "> Term 2 View the detailed schedule for Term 2. Term 3 Chronogram "> Term 3 View the detailed schedule for Term 3. Developers IRASUBIZA Jean Cadeau IHIRWE Aimee Saina HABAKUBAHO Brainy Justin TUMURAMYWE Placide Email: lycemuhur@gmail.com School Location Rwanda, Eastern Province Gatsibo District Muhura Sector, Taba Cell Kanyinya Village Follow Us © 2025 LYCEE SAINT ALEXANDRE SAULI DE MUHURA — All Rights Reserved', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('acc', 'main', 'Lycee S t Alexandre Sauli De Muhura Peres Barnabites', 'Lycee S t Alexandre Sauli De Muhura Peres Barnabites Home About Academic Staff Events Announcements Departments Fashion Design (FAD) Accounting ICT Software Development (SOD) Computer Systems & Architecture (CSA) Networking & Internet Technology (NIT) Contact Login Login Accounting Learn financial management, bookkeeping, and business decision-making. Financial Skills for the Future Students gain practical experience with financial software and reporting. Professional Accountants We train students for careers in finance, auditing, and business management. Curriculum Structure Senior 4 - Fundamentals of Accounting Introduction to bookkeeping, basic financial statements, and accounting principles. Senior 4 Senior 5 - Advanced Accounting Double-entry accounting, ledger preparation, trial balance, and financial analysis. Senior 5 Senior 6 - Accounting Applications & Projects Financial reporting, auditing basics, taxation, and practical accounting projects. Senior 6 Curriculum Details Senior 4 - Fundamentals of Accounting Introduction to accounting principles Single-entry bookkeeping Preparation of basic financial statements Understanding assets, liabilities, and equity View/Download Senior 4 NESA Chronogram Senior 5 - Advanced Accounting Double-entry bookkeeping Ledger preparation and trial balance Income statement and balance sheet preparation Financial analysis and interpretation View/Download Senior 5 NESA Chronogram Senior 6 - Accounting Applications & Projects Financial reporting and auditing basics Introduction to taxation and payroll accounting Practical accounting projects and case studies Preparation for higher education or professional certifications View/Download Senior 6 NESA Chronogram About Accounting Program The Accounting program at Lycee de Muhura develops students’ expertise in bookkeeping, financial reporting, and business management. Senior 4 introduces basic concepts, Senior 5 focuses on advanced accounting, and Senior 6 emphasizes applications and projects, preparing students for professional careers in finance and accounting. All departments Developers IRASUBIZA Jean Cadeau IHIRWE Aimee Saina HABAKUBAHO Brainy Justin TUMURAMYWE Placide Email: lycemuhur@gmail.com School Location Rwanda, Eastern Province Gatsibo District Muhura Sector, Taba Cell Kanyinya Village Follow Us © 2025 LYCEE SAINT ALEXANDRE SAULI DE MUHURA — All Rights Reserved', NULL);
